     1→import {execFile, execFileSync} from 'child_process';
     2→import path from 'path';
     3→
     4→import {Router} from 'express';
     5→
     6→import type {ActionResult, FetchPlansResult} from '../../shared/types.js';
     7→
     8→const router = Router();
     9→
    10→// erk is installed in the project's .venv/bin — add it to PATH for child processes
    11→const projectRoot = path.resolve(import.meta.dirname, '..', '..', '..', '..');
    12→const venvBin = path.join(projectRoot, '.venv', 'bin');
    13→const erkEnv = {...process.env, PATH: `${venvBin}:${process.env.PATH}`};
    14→
    15→// Resolve GitHub username once at startup (gh auth is assumed)
    16→const ghUsername = execFileSync('gh', ['api', 'user', '-q', '.login'], {
    17→  encoding: 'utf-8',
    18→}).trim();
    19→
    20→router.get('/plans', (_req, res) => {
    21→  execFile(
    22→    'erk',
    23→    ['exec', 'dash-data', '--creator', ghUsername],
    24→    {env: erkEnv},
    25→    (error, stdout, stderr) => {
    26→      if (error) {
    27→        const result: FetchPlansResult = {
    28→          success: false,
    29→          plans: [],
    30→          count: 0,
    31→          error: stderr || error.message,
    32→        };
    33→        res.json(result);
    34→        return;
    35→      }
    36→      try {
    37→        const data = JSON.parse(stdout);
    38→        const result: FetchPlansResult = {
    39→          success: true,
    40→          plans: data.plans ?? data,
    41→          count: data.count ?? (data.plans ?? data).length,
    42→        };
    43→        res.json(result);
    44→      } catch (parseError) {
    45→        const result: FetchPlansResult = {
    46→          success: false,
    47→          plans: [],
    48→          count: 0,
    49→          error: `Failed to parse erk output: ${parseError}`,
    50→        };
    51→        res.json(result);
    52→      }
    53→    },
    54→  );
    55→});
    56→
    57→/**
    58→ * Resolve the worktree path for a plan's branch by parsing `git worktree list --porcelain`.
    59→ * Returns the worktree path if found, or null.
    60→ */
    61→function resolveWorktreePath(branch: string): string | null {
    62→  try {
    63→    const output = execFileSync('git', ['worktree', 'list', '--porcelain'], {
    64→      cwd: projectRoot,
    65→      encoding: 'utf-8',
    66→    });
    67→    let currentPath: string | null = null;
    68→    for (const line of output.split('\n')) {
    69→      if (line.startsWith('worktree ')) {
    70→        currentPath = line.slice('worktree '.length);
    71→      } else if (line.startsWith('branch refs/heads/') && currentPath) {
    72→        if (line.slice('branch refs/heads/'.length) === branch) {
    73→          return currentPath;
    74→        }
    75→      }
    76→    }
    77→  } catch {
    78→    // git not available
    79→  }
    80→  return null;
    81→}
    82→
    83→/**
    84→ * Look up a plan's worktree path by issue number via dash-data + git worktree list.
    85→ */
    86→function resolveWorktreePathForIssue(
    87→  issueNumber: string,
    88→  callback: (error: string | null, worktreePath: string | null) => void,
    89→) {
    90→  execFile(
    91→    'erk',
    92→    ['exec', 'dash-data', '--creator', ghUsername],
    93→    {env: erkEnv},
    94→    (dataError, dataStdout) => {
    95→      if (dataError) {
    96→        callback('Failed to fetch plan data', null);
    97→        return;
    98→      }
    99→      try {
   100→        const data = JSON.parse(dataStdout);
   101→        const plans: Array<{issue_number: number; worktree_branch: string | null}> =
   102→          data.plans ?? data;
   103→        const plan = plans.find((p) => String(p.issue_number) === issueNumber);
